const IowaFootballMasterDB = () => {
  const [tab, setTab] = useState('games'); // games | players
  const [view, setView] = useState('season'); // season | detail (for games tab)
  const [selectedSeason, setSelectedSeason] = useState('all');
  const [selectedGame, setSelectedGame] = useState(null);
  const [selectedPlayer, setSelectedPlayer] = useState(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [playerSearch, setPlayerSearch] = useState('');
  const [sortBy, setSortBy] = useState('date');
  const [sortDir, setSortDir] = useState('asc');
  const [playerSortBy, setPlayerSortBy] = useState('total');

  const seasons = useMemo(() => [...new Set(GAMES_DATA.map(g => g.season))].sort(), []);

  const seasonRecords = useMemo(() => {
    const records = {};
    seasons.forEach(season => {
      const games = GAMES_DATA.filter(g => g.season === season);
      records[season] = {
        wins: games.filter(g => g.result === 'W').length,
        losses: games.filter(g => g.result === 'L').length,
        total: games.length
      };
    });
    return records;
  }, [seasons]);

  const filteredGames = useMemo(() => {
    let games = GAMES_DATA;
    if (selectedSeason !== 'all') games = games.filter(g => g.season === parseInt(selectedSeason));
    if (searchTerm) {
      const term = searchTerm.toLowerCase();
      games = games.filter(g =>
        g.opponent.toLowerCase().includes(term) ||
        g.location.toLowerCase().includes(term) ||
        String(g.season).includes(term) ||
        String(g.iowa_score).includes(term) ||
        String(g.opp_score).includes(term)
      );
    }
    games = [...games].sort((a, b) => {
      let aVal = a[sortBy], bVal = b[sortBy];
      if (sortBy === 'date') { aVal = new Date(a.date).getTime(); bVal = new Date(b.date).getTime(); }
      if (typeof aVal === 'string') return sortDir === 'asc' ? aVal.localeCompare(bVal) : bVal.localeCompare(aVal);
      return sortDir === 'asc' ? aVal - bVal : bVal - aVal;
    });
    return games;
  }, [selectedSeason, searchTerm, sortBy, sortDir]);

  const overallStats = useMemo(() => {
    const wins = GAMES_DATA.filter(g => g.result === 'W').length;
    const losses = GAMES_DATA.filter(g => g.result === 'L').length;
    return { wins, losses, total: GAMES_DATA.length };
  }, []);

  const playerList = useMemo(() => {
    let entries = Object.entries(PLAYERS_DATA);
    if (playerSearch) {
      const term = playerSearch.toLowerCase();
      entries = entries.filter(([name]) => name.toLowerCase().includes(term));
    }
    entries = entries.map(([name, p]) => {
      const c = p.career;
      const passYds = c.passing?.yds || 0;
      const rushYds = c.rushing?.net || 0;
      const recYds = c.receiving?.yds || 0;
      return { name, ...p, passYds, rushYds, recYds, totalYds: passYds + rushYds + recYds };
    });
    entries.sort((a, b) => {
      if (playerSortBy === 'total') return b.totalYds - a.totalYds;
      if (playerSortBy === 'pass') return b.passYds - a.passYds;
      if (playerSortBy === 'rush') return b.rushYds - a.rushYds;
      if (playerSortBy === 'rec') return b.recYds - a.recYds;
      if (playerSortBy === 'games') return b.total_games - a.total_games;
      return 0;
    });
    return entries;
  }, [playerSearch, playerSortBy]);

  const handleSort = (col) => {
    if (sortBy === col) setSortDir(sortDir === 'asc' ? 'desc' : 'asc');
    else { setSortBy(col); setSortDir('asc'); }
  };

  const formatDate = (dateStr) => {
    const d = new Date(dateStr + 'T12:00:00');
    return d.toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' });
  };

  const StatCard = ({ label, value, color = '#000' }) => (
    <div style={{ backgroundColor: '#fff', border: '1px solid #d0ccc6', borderRadius: '10px', padding: '18px', textAlign: 'center' }}>
      <div style={{ fontSize: '12px', color: '#999', marginBottom: '6px', textTransform: 'uppercase', fontWeight: '600' }}>{label}</div>
      <div style={{ fontSize: '28px', fontWeight: '700', color }}>{value}</div>
    </div>
  );

  const InfoItem = ({ icon, label, value }) => (
    <div>
      <div style={{ display: 'flex', alignItems: 'center', gap: '6px', opacity: 0.6, marginBottom: '4px' }}>{icon}<span>{label}</span></div>
      <div style={{ fontWeight: '600', fontSize: '13px' }}>{value}</div>
    </div>
  );

  // ============ SEASON OVERVIEW ============
  const SeasonView = () => (
    <div>
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(160px, 1fr))', gap: '16px', marginBottom: '32px' }}>
        <StatCard label="Total Games" value={overallStats.total} />
        <StatCard label="Total Wins" value={overallStats.wins} color="#0b7c0b" />
        <StatCard label="Total Losses" value={overallStats.losses} color="#c90000" />
        <StatCard label="Win %" value={`${((overallStats.wins/overallStats.total)*100).toFixed(0)}%`} color="#0066cc" />
      </div>

      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(140px, 1fr))', gap: '12px', marginBottom: '24px' }}>
        {seasons.map(season => {
          const rec = seasonRecords[season];
          const active = selectedSeason === String(season);
          return (
            <div key={season} onClick={() => setSelectedSeason(active ? 'all' : String(season))}
              style={{
                backgroundColor: active ? '#1a1a1a' : '#fff', color: active ? '#fff' : '#000',
                border: '2px solid ' + (active ? '#ffd700' : '#d0ccc6'), borderRadius: '10px',
                padding: '16px', cursor: 'pointer', textAlign: 'center', transition: 'all 0.2s'
              }}>
              <div style={{ fontSize: '20px', fontWeight: '700' }}>{season}</div>
              <div style={{ fontSize: '14px', opacity: 0.8, marginTop: '4px' }}>{rec.wins}-{rec.losses}</div>
            </div>
          );
        })}
      </div>

      <GamesTable />
    </div>
  );

  const GamesTable = () => (
    <div style={{ backgroundColor: '#fff', border: '1px solid #d0ccc6', borderRadius: '12px', overflow: 'hidden' }}>
      <div style={{ padding: '16px 20px', borderBottom: '1px solid #d0ccc6', backgroundColor: '#f8f7f4' }}>
        <h3 style={{ margin: 0, fontSize: '16px', fontWeight: '700' }}>
          {selectedSeason === 'all' ? 'All Games' : `${selectedSeason} Season`} ({filteredGames.length})
        </h3>
      </div>
      <div style={{ overflowX: 'auto' }}>
        <table style={{ width: '100%', borderCollapse: 'collapse' }}>
          <thead>
            <tr style={{ backgroundColor: '#f5f3f0', borderBottom: '1px solid #d0ccc6' }}>
              {[{key:'season',label:'Yr'},{key:'date',label:'Date'},{key:'opponent',label:'Opponent'},
                {key:'location',label:'Location'},{key:'result',label:'Result'},{key:'margin',label:'Score'},
                {key:'attendance',label:'Att.'}].map(col => (
                <th key={col.key} onClick={() => handleSort(col.key)}
                  style={{ padding: '10px 14px', textAlign: 'left', fontSize: '11px', fontWeight: '700', color: '#666',
                    cursor: 'pointer', userSelect: 'none', backgroundColor: sortBy === col.key ? '#e8e2d8' : 'transparent', whiteSpace: 'nowrap' }}>
                  {col.label} {sortBy === col.key ? (sortDir === 'asc' ? '↑' : '↓') : ''}
                </th>
              ))}
            </tr>
          </thead>
          <tbody>
            {filteredGames.map((game, idx) => (
              <tr key={game.id} onClick={() => { setSelectedGame(game); setView('detail'); }}
                style={{ borderBottom: '1px solid #e8e4de', backgroundColor: idx % 2 === 0 ? '#fff' : '#fafaf9', cursor: 'pointer' }}
                onMouseEnter={(e) => e.currentTarget.style.backgroundColor = '#f0ede7'}
                onMouseLeave={(e) => e.currentTarget.style.backgroundColor = idx % 2 === 0 ? '#fff' : '#fafaf9'}>
                <td style={{ padding: '10px 14px', fontSize: '13px', color: '#999', fontWeight: '600' }}>{game.season}</td>
                <td style={{ padding: '10px 14px', fontSize: '13px', color: '#333', whiteSpace: 'nowrap' }}>{formatDate(game.date)}</td>
                <td style={{ padding: '10px 14px', fontSize: '14px', fontWeight: '600', color: '#000' }}>
                  {game.opponent}{game.bowl_name && <span style={{ fontSize: '11px', color: '#0066cc', marginLeft: '6px' }}>({game.bowl_name})</span>}
                </td>
                <td style={{ padding: '10px 14px', fontSize: '12px', color: '#666' }}>{game.location}</td>
                <td style={{ padding: '10px 14px', fontSize: '13px', fontWeight: '700', color: game.result === 'W' ? '#0b7c0b' : '#c90000' }}>
                  {game.result === 'W' ? '✓ W' : '✕ L'}
                </td>
                <td style={{ padding: '10px 14px', fontWeight: '700', color: '#000', whiteSpace: 'nowrap' }}>{game.iowa_score}-{game.opp_score}</td>
                <td style={{ padding: '10px 14px', fontSize: '12px', color: '#666' }}>{game.attendance ? `${(game.attendance/1000).toFixed(0)}K` : '—'}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
      {filteredGames.length === 0 && <div style={{ padding: '40px', textAlign: 'center', color: '#999' }}>No games found.</div>}
    </div>
  );

  const DetailView = () => {
    if (!selectedGame) return null;
    const g = selectedGame;
    const s = g.stats;

    const StatRow = ({ label, iowa, opp, suffix = '' }) => {
      if (iowa === null || iowa === undefined) return null;
      return (
        <div style={{ display: 'grid', gridTemplateColumns: '1fr 100px 1fr', alignItems: 'center', padding: '10px 0', borderBottom: '1px solid #f0ede7' }}>
          <div style={{ textAlign: 'right', fontWeight: '700', fontSize: '15px', color: '#000', paddingRight: '12px' }}>{iowa}{suffix}</div>
          <div style={{ textAlign: 'center', fontSize: '11px', color: '#999', textTransform: 'uppercase', fontWeight: '600' }}>{label}</div>
          <div style={{ textAlign: 'left', fontWeight: '700', fontSize: '15px', color: '#000', paddingLeft: '12px' }}>{opp}{suffix}</div>
        </div>
      );
    };

    return (
      <div>
        <button onClick={() => setView('season')} style={{ backgroundColor: 'transparent', border: 'none', fontSize: '14px', color: '#0066cc', cursor: 'pointer', marginBottom: '20px', fontWeight: '600', display: 'flex', alignItems: 'center', gap: '4px' }}>
          <ChevronLeft size={16} /> Back to Games
        </button>

        <div style={{ backgroundColor: '#1a1a1a', color: '#fff', borderRadius: '12px', padding: '28px', marginBottom: '24px' }}>
          <div style={{ fontSize: '13px', opacity: 0.7, marginBottom: '12px' }}>
            {g.season} SEASON {g.bowl_name && `• ${g.bowl_name.toUpperCase()}`}
          </div>
          <div style={{ display: 'grid', gridTemplateColumns: '1fr auto 1fr', alignItems: 'center', gap: '20px', marginBottom: '20px' }}>
            <div style={{ textAlign: 'right' }}>
              <div style={{ fontSize: '22px', fontWeight: '700', marginBottom: '8px' }}>Iowa</div>
              <div style={{ fontSize: '52px', fontWeight: '700', color: '#ffd700' }}>{g.iowa_score}</div>
            </div>
            <div style={{ fontSize: '24px', opacity: 0.5 }}>—</div>
            <div style={{ textAlign: 'left' }}>
              <div style={{ fontSize: '22px', fontWeight: '700', marginBottom: '8px' }}>{g.opponent}</div>
              <div style={{ fontSize: '52px', fontWeight: '700' }}>{g.opp_score}</div>
            </div>
          </div>
          <div style={{ textAlign: 'center', fontSize: '16px', fontWeight: '700', color: g.result === 'W' ? '#90ee90' : '#ff6b6b', marginBottom: '20px' }}>
            {g.result === 'W' ? 'IOWA WINS' : 'IOWA LOSES'} • Margin: {Math.abs(g.margin)}
          </div>
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(140px, 1fr))', gap: '14px', fontSize: '12px', paddingTop: '20px', borderTop: '1px solid #333' }}>
            <InfoItem icon={<Calendar size={14} />} label="Date" value={formatDate(g.date)} />
            <InfoItem icon={<MapPin size={14} />} label="Location" value={g.location} />
            {g.attendance && <InfoItem icon={<Users size={14} />} label="Attendance" value={g.attendance.toLocaleString()} />}
            {g.weather && <InfoItem icon={<Cloud size={14} />} label="Weather" value={g.weather} />}
          </div>
        </div>

        {g.note && (
          <div style={{ backgroundColor: '#fff9e6', border: '1px solid #ffe58f', borderRadius: '10px', padding: '16px', marginBottom: '24px', fontSize: '14px', color: '#664d03' }}>
            📌 {g.note}
          </div>
        )}

        {g.iowa_quarters && g.iowa_quarters.length > 1 && (
          <div style={{ backgroundColor: '#fff', border: '1px solid #d0ccc6', borderRadius: '12px', padding: '20px', marginBottom: '24px' }}>
            <h3 style={{ margin: '0 0 16px 0', fontSize: '15px', fontWeight: '700' }}>Scoring by Quarter</h3>
            <table style={{ width: '100%', borderCollapse: 'collapse' }}>
              <thead>
                <tr>
                  <th style={{ textAlign: 'left', padding: '6px', fontSize: '12px', color: '#999' }}></th>
                  {g.iowa_quarters.map((_, i) => <th key={i} style={{ textAlign: 'center', padding: '6px', fontSize: '12px', color: '#999' }}>Q{i+1}</th>)}
                  <th style={{ textAlign: 'center', padding: '6px', fontSize: '12px', color: '#999', fontWeight: '700' }}>Final</th>
                </tr>
              </thead>
              <tbody>
                <tr>
                  <td style={{ padding: '6px', fontWeight: '700', fontSize: '13px' }}>Iowa</td>
                  {g.iowa_quarters.map((q, i) => <td key={i} style={{ textAlign: 'center', padding: '6px', fontSize: '13px' }}>{q}</td>)}
                  <td style={{ textAlign: 'center', padding: '6px', fontWeight: '700', fontSize: '13px' }}>{g.iowa_score}</td>
                </tr>
                <tr>
                  <td style={{ padding: '6px', fontWeight: '700', fontSize: '13px' }}>{g.opponent}</td>
                  {g.opp_quarters.map((q, i) => <td key={i} style={{ textAlign: 'center', padding: '6px', fontSize: '13px' }}>{q}</td>)}
                  <td style={{ textAlign: 'center', padding: '6px', fontWeight: '700', fontSize: '13px' }}>{g.opp_score}</td>
                </tr>
              </tbody>
            </table>
          </div>
        )}

        <div style={{ backgroundColor: '#fff', border: '1px solid #d0ccc6', borderRadius: '12px', padding: '20px' }}>
          <h3 style={{ margin: '0 0 8px 0', fontSize: '15px', fontWeight: '700', textAlign: 'center' }}>Team Statistics</h3>
          <div style={{ display: 'grid', gridTemplateColumns: '1fr 100px 1fr', marginBottom: '8px' }}>
            <div style={{ textAlign: 'right', fontSize: '12px', fontWeight: '700', color: '#0066cc' }}>IOWA</div><div></div>
            <div style={{ textAlign: 'left', fontSize: '12px', fontWeight: '700', color: '#c90000' }}>{g.opponent.toUpperCase()}</div>
          </div>
          <StatRow label="First Downs" iowa={s.first_downs.iowa} opp={s.first_downs.opp} />
          <StatRow label="Rushing Yards" iowa={s.rushing_yards.iowa} opp={s.rushing_yards.opp} />
          <StatRow label="Passing Yards" iowa={s.passing_yards.iowa} opp={s.passing_yards.opp} />
          <StatRow label="Total Yards" iowa={s.total_yards.iowa} opp={s.total_yards.opp} />
          <StatRow label="Passes Comp-Att" iowa={s.passes_completed.iowa != null ? `${s.passes_completed.iowa}-${s.passes_attempted.iowa}` : null} opp={s.passes_completed.opp != null ? `${s.passes_completed.opp}-${s.passes_attempted.opp}` : null} />
          <StatRow label="Interceptions Thrown" iowa={s.interceptions_thrown.iowa} opp={s.interceptions_thrown.opp} />
          <StatRow label="Possession Time" iowa={s.possession_time.iowa} opp={s.possession_time.opp} />
        </div>

        {g.officials && <div style={{ marginTop: '20px', fontSize: '12px', color: '#999', textAlign: 'center' }}>Officials: {g.officials}</div>}
      </div>
    );
  };

  // ============ PLAYERS TAB ============
  const PlayersListView = () => (
    <div>
      <div style={{ display: 'flex', gap: '12px', marginBottom: '20px', flexWrap: 'wrap', alignItems: 'center' }}>
        <div style={{ position: 'relative', flex: '1', minWidth: '200px' }}>
          <Search size={16} style={{ position: 'absolute', left: '12px', top: '12px', color: '#999' }} />
          <input
            type="text" placeholder="Search players..." value={playerSearch}
            onChange={(e) => setPlayerSearch(e.target.value)}
            style={{ width: '100%', padding: '10px 12px 10px 36px', border: '1px solid #d0ccc6', borderRadius: '8px', fontSize: '14px', boxSizing: 'border-box' }}
          />
        </div>
        <select value={playerSortBy} onChange={(e) => setPlayerSortBy(e.target.value)}
          style={{ padding: '10px 14px', border: '1px solid #d0ccc6', borderRadius: '8px', fontSize: '13px', fontWeight: '600', cursor: 'pointer', backgroundColor: '#fff' }}>
          <option value="total">Sort: Total Yards</option>
          <option value="pass">Sort: Passing Yards</option>
          <option value="rush">Sort: Rushing Yards</option>
          <option value="rec">Sort: Receiving Yards</option>
          <option value="games">Sort: Games Played</option>
        </select>
      </div>

      <div style={{ backgroundColor: '#fff', border: '1px solid #d0ccc6', borderRadius: '12px', overflow: 'hidden' }}>
        <div style={{ padding: '16px 20px', borderBottom: '1px solid #d0ccc6', backgroundColor: '#f8f7f4' }}>
          <h3 style={{ margin: 0, fontSize: '16px', fontWeight: '700' }}>Player Career Stats ({playerList.length})</h3>
          <p style={{ margin: '4px 0 0 0', fontSize: '12px', color: '#999' }}>Aggregated from individual game box scores, 2001-2005</p>
        </div>
        <div style={{ overflowX: 'auto' }}>
          <table style={{ width: '100%', borderCollapse: 'collapse' }}>
            <thead>
              <tr style={{ backgroundColor: '#f5f3f0', borderBottom: '1px solid #d0ccc6' }}>
                <th style={{ padding: '10px 14px', textAlign: 'left', fontSize: '11px', fontWeight: '700', color: '#666' }}>Player</th>
                <th style={{ padding: '10px 14px', textAlign: 'left', fontSize: '11px', fontWeight: '700', color: '#666' }}>Years</th>
                <th style={{ padding: '10px 14px', textAlign: 'center', fontSize: '11px', fontWeight: '700', color: '#666' }}>Games</th>
                <th style={{ padding: '10px 14px', textAlign: 'right', fontSize: '11px', fontWeight: '700', color: '#666' }}>Pass Yds</th>
                <th style={{ padding: '10px 14px', textAlign: 'right', fontSize: '11px', fontWeight: '700', color: '#666' }}>Rush Yds</th>
                <th style={{ padding: '10px 14px', textAlign: 'right', fontSize: '11px', fontWeight: '700', color: '#666' }}>Rec Yds</th>
                <th style={{ padding: '10px 14px', textAlign: 'right', fontSize: '11px', fontWeight: '700', color: '#666' }}>Total</th>
              </tr>
            </thead>
            <tbody>
              {playerList.map((p, idx) => (
                <tr key={p.name} onClick={() => setSelectedPlayer(p)}
                  style={{ borderBottom: '1px solid #e8e4de', backgroundColor: idx % 2 === 0 ? '#fff' : '#fafaf9', cursor: 'pointer' }}
                  onMouseEnter={(e) => e.currentTarget.style.backgroundColor = '#f0ede7'}
                  onMouseLeave={(e) => e.currentTarget.style.backgroundColor = idx % 2 === 0 ? '#fff' : '#fafaf9'}>
                  <td style={{ padding: '10px 14px', fontSize: '14px', fontWeight: '600', color: '#000' }}>{p.name}</td>
                  <td style={{ padding: '10px 14px', fontSize: '12px', color: '#666' }}>{p.years_active.join(', ')}</td>
                  <td style={{ padding: '10px 14px', fontSize: '13px', textAlign: 'center', color: '#666' }}>{p.total_games}</td>
                  <td style={{ padding: '10px 14px', fontSize: '13px', textAlign: 'right', color: p.passYds > 0 ? '#000' : '#ccc' }}>{p.passYds ? p.passYds.toFixed(0) : '—'}</td>
                  <td style={{ padding: '10px 14px', fontSize: '13px', textAlign: 'right', color: p.rushYds !== 0 ? '#000' : '#ccc' }}>{p.rushYds ? p.rushYds.toFixed(0) : '—'}</td>
                  <td style={{ padding: '10px 14px', fontSize: '13px', textAlign: 'right', color: p.recYds > 0 ? '#000' : '#ccc' }}>{p.recYds ? p.recYds.toFixed(0) : '—'}</td>
                  <td style={{ padding: '10px 14px', fontSize: '14px', textAlign: 'right', fontWeight: '700', color: '#0066cc' }}>{p.totalYds.toFixed(0)}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
        {playerList.length === 0 && <div style={{ padding: '40px', textAlign: 'center', color: '#999' }}>No players found.</div>}
      </div>
    </div>
  );

  const PlayerDetailView = () => {
    if (!selectedPlayer) return null;
    const p = selectedPlayer;
    const seasonYears = Object.keys(p.seasons).sort();

    const CatBlock = ({ title, stats, fields }) => {
      if (!stats || Object.keys(stats).length === 0) return null;
      return (
        <div style={{ marginBottom: '16px' }}>
          <div style={{ fontSize: '12px', fontWeight: '700', color: '#999', marginBottom: '6px', textTransform: 'uppercase' }}>{title}</div>
          <div style={{ display: 'flex', gap: '20px', flexWrap: 'wrap' }}>
            {fields.map(([key, label]) => stats[key] !== undefined && (
              <div key={key}>
                <span style={{ fontSize: '18px', fontWeight: '700', color: '#000' }}>{stats[key]}</span>
                <span style={{ fontSize: '11px', color: '#999', marginLeft: '4px' }}>{label}</span>
              </div>
            ))}
          </div>
        </div>
      );
    };

    return (
      <div>
        <button onClick={() => setSelectedPlayer(null)} style={{ backgroundColor: 'transparent', border: 'none', fontSize: '14px', color: '#0066cc', cursor: 'pointer', marginBottom: '20px', fontWeight: '600', display: 'flex', alignItems: 'center', gap: '4px' }}>
          <ChevronLeft size={16} /> Back to Players
        </button>

        <div style={{ backgroundColor: '#1a1a1a', color: '#fff', borderRadius: '12px', padding: '28px', marginBottom: '24px' }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: '10px', marginBottom: '8px' }}>
            <Award size={24} color="#ffd700" />
            <h2 style={{ margin: 0, fontSize: '26px', fontWeight: '700' }}>{p.name}</h2>
          </div>
          <div style={{ fontSize: '13px', opacity: 0.8 }}>
            Iowa Hawkeyes • {p.years_active.join(', ')} • {p.total_games} games tracked
          </div>
        </div>

        <div style={{ backgroundColor: '#fff', border: '1px solid #d0ccc6', borderRadius: '12px', padding: '24px', marginBottom: '24px' }}>
          <h3 style={{ margin: '0 0 16px 0', fontSize: '15px', fontWeight: '700', display: 'flex', alignItems: 'center', gap: '6px' }}>
            <TrendingUp size={16} /> Career Totals
          </h3>
          <CatBlock title="Passing" stats={p.career.passing} fields={[['att','Att'],['cmp','Cmp'],['yds','Yds'],['td','TD'],['int','INT'],['long','Long']]} />
          <CatBlock title="Rushing" stats={p.career.rushing} fields={[['no','Car'],['net','Yds'],['td','TD'],['lg','Long']]} />
          <CatBlock title="Receiving" stats={p.career.receiving} fields={[['no','Rec'],['yds','Yds'],['td','TD'],['long','Long']]} />
        </div>

        <div style={{ backgroundColor: '#fff', border: '1px solid #d0ccc6', borderRadius: '12px', padding: '24px' }}>
          <h3 style={{ margin: '0 0 16px 0', fontSize: '15px', fontWeight: '700' }}>Season-by-Season Breakdown</h3>
          {seasonYears.map(year => {
            const s = p.seasons[year];
            return (
              <div key={year} style={{ marginBottom: '20px', paddingBottom: '20px', borderBottom: year !== seasonYears[seasonYears.length-1] ? '1px solid #f0ede7' : 'none' }}>
                <div style={{ fontSize: '16px', fontWeight: '700', color: '#0066cc', marginBottom: '10px' }}>
                  {year} <span style={{ fontSize: '12px', color: '#999', fontWeight: '400' }}>({s.games_played} games)</span>
                </div>
                <CatBlock title="Passing" stats={s.passing} fields={[['att','Att'],['cmp','Cmp'],['yds','Yds'],['td','TD'],['int','INT']]} />
                <CatBlock title="Rushing" stats={s.rushing} fields={[['no','Car'],['net','Yds'],['td','TD'],['lg','Long']]} />
                <CatBlock title="Receiving" stats={s.receiving} fields={[['no','Rec'],['yds','Yds'],['td','TD'],['long','Long']]} />
              </div>
            );
          })}
        </div>
      </div>
    );
  };

  return (
    <div style={{ backgroundColor: '#f8f7f4', minHeight: '100vh', fontFamily: "'Inter', -apple-system, sans-serif" }}>
      <div style={{ backgroundColor: '#000', color: '#fff', padding: '28px 20px', borderBottom: '4px solid #ffd700' }}>
        <div style={{ maxWidth: '1100px', margin: '0 auto' }}>
          <h1 style={{ fontSize: '28px', fontWeight: '700', margin: '0 0 8px 0' }}>Iowa Hawkeyes Football</h1>
          <p style={{ fontSize: '14px', opacity: 0.85, margin: 0 }}>Master Database • 2001-2005 • {overallStats.total} Games • {Object.keys(PLAYERS_DATA).length} Players Tracked</p>
        </div>
      </div>

      {/* Tab nav */}
      <div style={{ backgroundColor: '#fff', borderBottom: '1px solid #d0ccc6' }}>
        <div style={{ maxWidth: '1100px', margin: '0 auto', display: 'flex' }}>
          {[
            { key: 'games', label: 'Games', icon: <Calendar size={16} /> },
            { key: 'players', label: 'Players', icon: <Users size={16} /> },
          ].map(t => (
            <button key={t.key} onClick={() => { setTab(t.key); setSelectedPlayer(null); setView('season'); }}
              style={{
                backgroundColor: 'transparent', border: 'none', padding: '14px 24px', fontSize: '14px',
                fontWeight: tab === t.key ? '700' : '600', color: tab === t.key ? '#000' : '#999',
                borderBottom: tab === t.key ? '3px solid #ffd700' : '3px solid transparent',
                cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '8px'
              }}>
              {t.icon} {t.label}
            </button>
          ))}
        </div>
      </div>

      {tab === 'games' && view === 'season' && (
        <div style={{ backgroundColor: '#fff', borderBottom: '1px solid #d0ccc6', padding: '16px 20px' }}>
          <div style={{ maxWidth: '1100px', margin: '0 auto', position: 'relative' }}>
            <Search size={16} style={{ position: 'absolute', left: '12px', top: '12px', color: '#999' }} />
            <input type="text" placeholder="Search by opponent, location, score, or year..." value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              style={{ width: '100%', padding: '10px 12px 10px 36px', border: '1px solid #d0ccc6', borderRadius: '8px', fontSize: '14px', boxSizing: 'border-box' }} />
          </div>
        </div>
      )}

      <div style={{ maxWidth: '1100px', margin: '0 auto', padding: '28px 20px' }}>
        {tab === 'games' && view === 'season' && <SeasonView />}
        {tab === 'games' && view === 'detail' && <DetailView />}
        {tab === 'players' && !selectedPlayer && <PlayersListView />}
        {tab === 'players' && selectedPlayer && <PlayerDetailView />}
      </div>

      <div style={{ borderTop: '1px solid #d0ccc6', backgroundColor: '#fff', padding: '20px', textAlign: 'center', color: '#999', fontSize: '13px' }}>
        Iowa Hawkeyes Football Database • {seasons.join(', ')} Seasons • {overallStats.wins}-{overallStats.losses} Overall
      </div>
    </div>
  );
};

export default IowaFootballMasterDB;
